const express = require('express');
const session = require('express-session');
const twilio = require('twilio');

// Twilio account settings
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// Express app setup
const app = express();
app.use(session({
  secret: 'secret_key',
  resave: false,
  saveUninitialized: true
}));

// Generate random 6-digit code
function generateCode() {
  const characters = '0123456789';
  let code = '';
  for (let i = 0; i < 6; i++) {
    code += characters.charAt(Math.floor(Math.random() * characters.length));
  }
  return code;
}

// Send SMS using Twilio
function sendSMS(phoneNumber, code) {
  const message = client.messages.create({
    from: 'your_twilio_phone_number',
    to: phoneNumber,
    body: `Your verification code is ${code}`
  });
}

// Verify user input
function verifyCode(code, sessionCode) {
  return code === sessionCode;
}

// Route for generating and sending SMS code
app.post('/generate-code', (req, res) => {
  const phoneNumber = req.body.phoneNumber;
  const code = generateCode();
  sendSMS(phoneNumber, code);
  req.session.code = code;
  res.send(`Verification code sent to ${phoneNumber}`);
});

// Route for verifying user input
app.post('/verify-code', (req, res) => {
  const code = req.body.code;
  if (verifyCode(code, req.session.code)) {
    res.send('Authentication successful');
  } else {
    res.status(401).send('Invalid verification code');
  }
});

// Start server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});